  1	import {
  2	  Button,
  3	  Dropdown,
  4	  DropdownItem,
  5	  MenuToggle,
  6	  MenuToggleElement,
  7	  OverflowMenu,
  8	  OverflowMenuContent,
  9	  OverflowMenuControl,
 10	  OverflowMenuGroup,
 11	  OverflowMenuItem
 12	} from '@patternfly/react-core';
 13	import { EllipsisVIcon } from '@patternfly/react-icons';
 14	import * as React from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import { MaybeTooltip } from '../tooltip/maybe-tooltip';
 17	
 18	export interface Item {
 19	  id: string;
 20	  icon?: JSX.Element;
 21	  label: string;
 22	  tooltip?: React.ReactNode;
 23	  onClick: () => void;
 24	  enabled?: boolean;
 25	}
 26	
 27	export interface LinksOverflowProps {
 28	  id: string;
 29	  items: Item[];
 30	  text?: string;
 31	}
 32	
 33	export const LinksOverflow: React.FC<LinksOverflowProps> = ({ id, items, text }) => {
 34	  const { t } = useTranslation('plugin__netobserv-plugin');
 35	  const [isOpen, setOpen] = React.useState(false);
 36	
 37	  const enabledItems = items.filter(i => i.enabled !== false);
 38	  if (enabledItems.length === 0) {
 39	    return null;
 40	  } else if (enabledItems.length === 1) {
 41	    const item = enabledItems[0];
 42	    return (
 43	      <MaybeTooltip content={item.tooltip}>
 44	        <Button
 45	          data-test={item.id + '-button'}
 46	          id={item.id + '-button'}
 47	          variant="link"
 48	          className="overflow-button"
 49	          icon={item.icon}
 50	          onClick={item.onClick}
 51	        >
 52	          {item.label}
 53	        </Button>
 54	      </MaybeTooltip>
 55	    );
 56	  }
 57	
 58	  return (
 59	    <OverflowMenu breakpoint="2xl">
 60	      <OverflowMenuContent isPersistent>
 61	        <OverflowMenuGroup groupType="button" isPersistent className="toolbar-group flex-start">
 62	          {enabledItems.map(item => (
 63	            <OverflowMenuItem key={item.id}>
 64	              <MaybeTooltip content={item.tooltip}>
 65	                <Button
 66	                  data-test={item.id + '-button'}
 67	                  id={item.id + '-button'}
 68	                  variant="link"
 69	                  className="overflow-button"
 70	                  icon={item.icon}
 71	                  onClick={item.onClick}
 72	                >
 73	                  {item.label}
 74	                </Button>
 75	              </MaybeTooltip>
 76	            </OverflowMenuItem>
 77	          ))}
 78	        </OverflowMenuGroup>
 79	      </OverflowMenuContent>
 80	      <OverflowMenuControl className="flex-start">
 81	        <Dropdown
 82	          data-test={id + '-dropdown'}
 83	          id={id + '-dropdown'}
 84	          onSelect={() => setOpen(false)}
 85	          isOpen={isOpen}
 86	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 87	            <MenuToggle
 88	              ref={toggleRef}
 89	              data-test={id + '-button'}
 90	              id={id + '-button'}
 91	              variant="plain"
 92	              className="overflow-button"
 93	              icon={<EllipsisVIcon />}
 94	              isExpanded={isOpen}
 95	              onClick={() => setOpen(!isOpen)}
 96	              onBlur={() => setTimeout(() => setOpen(false), 500)}
 97	            >
 98	              <>
 99	                <EllipsisVIcon /> {text || t('More options')}
100	              </>
101	            </MenuToggle>
102	          )}
103	        >
104	          {enabledItems.map(item => (
105	            <DropdownItem key={item.id} onClick={item.onClick} data-test={item.id + '-button'}>
106	              {item.label}
107	            </DropdownItem>
108	          ))}
109	        </Dropdown>
110	      </OverflowMenuControl>
111	    </OverflowMenu>
112	  );
113	};

